import { useState, useEffect } from "react";
import QuestionList from "../components/QuestionList";

const TAGS = [
  { name: "python", count: 142 },
  { name: "javascript", count: 98 },
  { name: "java", count: 76 },
  { name: "react", count: 64 },
  { name: "sql", count: 53 },
  { name: "typescript", count: 47 },
  { name: "node.js", count: 39 },
  { name: "css", count: 31 },
  { name: "rust", count: 18 },
  { name: "docker", count: 14 },
];

export default function Home() {
  const [mounted, setMounted] = useState(false);
  const [activeTag, setActiveTag] = useState(null);
  const [scanY, setScanY] = useState(0);

  useEffect(() => {
    setTimeout(() => setMounted(true), 80);
    const iv = setInterval(() => setScanY(v => (v + 0.5) % 100), 22);
    return () => clearInterval(iv);
  }, []);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;600;900&family=Share+Tech+Mono&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: #020c14; overflow-x: hidden; }

        .home-root {
          min-height: 100vh;
          background: #020c14;
          font-family: 'Share Tech Mono', monospace;
          position: relative;
          overflow: hidden;
        }

        /* Grid background */
        .home-root::before {
          content: '';
          position: fixed;
          inset: 0;
          background-image:
            linear-gradient(rgba(0,255,200,0.025) 1px, transparent 1px),
            linear-gradient(90deg, rgba(0,255,200,0.025) 1px, transparent 1px);
          background-size: 52px 52px;
          pointer-events: none;
          z-index: 0;
        }

        /* Radial glow */
        .home-root::after {
          content: '';
          position: fixed;
          inset: 0;
          background:
            radial-gradient(ellipse 60% 50% at 50% 0%, rgba(0,40,60,0.9) 0%, transparent 70%),
            radial-gradient(ellipse 40% 60% at 0% 100%, rgba(0,60,100,0.1) 0%, transparent 60%);
          pointer-events: none;
          z-index: 0;
        }

        .scanlines {
          position: fixed; inset: 0; z-index: 1;
          background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.06) 2px, rgba(0,0,0,0.06) 4px);
          pointer-events: none;
        }

        .scan-beam {
          position: fixed; left: 0; right: 0; height: 2px;
          background: linear-gradient(90deg, transparent, rgba(0,255,200,0.12), rgba(0,255,200,0.4), rgba(0,200,255,0.3), rgba(0,255,200,0.12), transparent);
          z-index: 2; pointer-events: none; filter: blur(1px);
        }

        /* Top nav bar */
        .topbar {
          position: relative; z-index: 10;
          border-bottom: 1px solid rgba(0,255,200,0.1);
          background: rgba(2,12,20,0.85);
          backdrop-filter: blur(20px);
          padding: 0 32px;
          display: flex; align-items: center; justify-content: space-between;
          height: 56px;
          opacity: 0; transform: translateY(-10px);
          transition: opacity 0.6s ease, transform 0.6s ease;
        }
        .topbar.on { opacity: 1; transform: translateY(0); }

        .topbar-logo {
          font-family: 'Orbitron', sans-serif;
          font-weight: 900;
          font-size: 16px;
          letter-spacing: 0.15em;
          color: #00ffc8;
          text-shadow: 0 0 20px rgba(0,255,200,0.5);
          text-transform: uppercase;
        }

        .topbar-logo span { color: rgba(0,200,255,0.7); }

        .topbar-right {
          display: flex; align-items: center; gap: 20px;
        }

        .topbar-stat {
          font-size: 10px; letter-spacing: 0.15em;
          color: rgba(0,255,200,0.4); text-transform: uppercase;
        }

        .topbar-stat strong { color: rgba(0,255,200,0.9); margin-right: 4px; }

        .topbar-dot { width: 6px; height: 6px; border-radius: 50%; background: #00ffc8; box-shadow: 0 0 8px #00ffc8; animation: blink 1.6s ease-in-out infinite; }
        @keyframes blink { 0%,100%{opacity:1;} 50%{opacity:0.2;} }

        /* Layout */
        .layout {
          position: relative; z-index: 5;
          display: flex;
          max-width: 1200px;
          margin: 0 auto;
          padding: 32px 24px;
          gap: 28px;
          opacity: 0; transform: translateY(20px);
          transition: opacity 0.7s 0.2s ease, transform 0.7s 0.2s ease;
        }
        .layout.on { opacity: 1; transform: translateY(0); }

        /* Sidebar */
        .sidebar {
          width: 220px;
          flex-shrink: 0;
        }

        .sidebar-header {
          display: flex; align-items: center; gap: 8px;
          margin-bottom: 16px;
        }

        .sidebar-title {
          font-family: 'Orbitron', sans-serif;
          font-size: 11px;
          font-weight: 600;
          letter-spacing: 0.3em;
          text-transform: uppercase;
          color: rgba(0,255,200,0.7);
        }

        .sidebar-title-line {
          flex: 1; height: 1px;
          background: linear-gradient(90deg, rgba(0,255,200,0.3), transparent);
        }

        .tag-item {
          display: flex; align-items: center; justify-content: space-between;
          padding: 8px 12px;
          margin-bottom: 4px;
          border: 1px solid rgba(0,255,200,0.08);
          background: rgba(0,255,200,0.02);
          cursor: pointer;
          transition: border-color 0.2s, background 0.2s, transform 0.15s;
          position: relative;
          overflow: hidden;
        }

        .tag-item::before {
          content: '';
          position: absolute;
          left: 0; top: 0; bottom: 0;
          width: 0;
          background: rgba(0,255,200,0.06);
          transition: width 0.25s ease;
        }

        .tag-item:hover::before, .tag-item.active::before { width: 100%; }
        .tag-item:hover, .tag-item.active {
          border-color: rgba(0,255,200,0.35);
          transform: translateX(3px);
        }

        .tag-item.active { border-color: rgba(0,255,200,0.5); }

        .tag-left {
          display: flex; align-items: center; gap: 8px;
          font-size: 12px; color: rgba(0,255,200,0.7);
          letter-spacing: 0.05em; position: relative;
        }

        .tag-item.active .tag-left { color: #00ffc8; }

        .tag-arrow {
          font-size: 9px; color: rgba(0,255,200,0.3);
          transition: color 0.2s;
        }
        .tag-item:hover .tag-arrow, .tag-item.active .tag-arrow { color: #00ffc8; }

        .tag-count {
          font-size: 10px;
          color: rgba(0,200,255,0.45);
          letter-spacing: 0.05em;
          position: relative;
        }

        /* Main content */
        .main { flex: 1; min-width: 0; }

        .main-header {
          display: flex; align-items: flex-start; justify-content: space-between;
          margin-bottom: 28px;
          flex-wrap: wrap; gap: 12px;
        }

        .main-title-group {}

        .main-eyebrow {
          font-size: 9px; letter-spacing: 0.3em; text-transform: uppercase;
          color: rgba(0,255,200,0.4); margin-bottom: 6px;
        }

        .main-title {
          font-family: 'Orbitron', sans-serif;
          font-size: 22px; font-weight: 900;
          color: #e6fff8; letter-spacing: 0.08em;
          text-transform: uppercase;
        }

        .main-title-accent { color: #00ffc8; }

        .ask-btn {
          display: flex; align-items: center; gap: 8px;
          padding: 10px 20px;
          background: transparent;
          border: 1px solid rgba(0,255,200,0.45);
          color: #00ffc8;
          font-family: 'Orbitron', sans-serif;
          font-size: 10px; font-weight: 700;
          letter-spacing: 0.25em; text-transform: uppercase;
          cursor: pointer;
          position: relative; overflow: hidden;
          transition: border-color 0.25s, box-shadow 0.25s, color 0.25s;
        }

        .ask-btn::before {
          content: '';
          position: absolute; inset: 0;
          background: linear-gradient(135deg, rgba(0,255,200,0.12), rgba(0,150,255,0.07));
          opacity: 0; transition: opacity 0.25s;
        }

        .ask-btn:hover::before { opacity: 1; }
        .ask-btn:hover {
          border-color: #00ffc8;
          box-shadow: 0 0 28px rgba(0,255,200,0.15);
          color: #fff;
        }

        .ask-btn-plus { font-size: 16px; line-height: 1; }

        /* Filter bar */
        .filter-bar {
          display: flex; align-items: center; gap: 8px;
          margin-bottom: 20px;
          padding-bottom: 16px;
          border-bottom: 1px solid rgba(0,255,200,0.07);
        }

        .filter-btn {
          padding: 5px 14px;
          font-family: 'Share Tech Mono', monospace;
          font-size: 10px; letter-spacing: 0.15em; text-transform: uppercase;
          background: transparent;
          border: 1px solid rgba(0,255,200,0.1);
          color: rgba(0,255,200,0.4);
          cursor: pointer;
          transition: border-color 0.2s, color 0.2s, background 0.2s;
        }

        .filter-btn:hover { border-color: rgba(0,255,200,0.3); color: rgba(0,255,200,0.7); }
        .filter-btn.active {
          border-color: rgba(0,255,200,0.5);
          color: #00ffc8;
          background: rgba(0,255,200,0.05);
        }

        .filter-sep { flex: 1; }

        .result-count {
          font-size: 10px; letter-spacing: 0.1em;
          color: rgba(0,255,200,0.3);
        }

        /* Active tag pill */
        .active-tag-pill {
          display: inline-flex; align-items: center; gap: 8px;
          padding: 4px 10px 4px 12px;
          border: 1px solid rgba(0,255,200,0.3);
          background: rgba(0,255,200,0.06);
          font-size: 11px; color: rgba(0,255,200,0.8);
          letter-spacing: 0.08em; margin-bottom: 16px;
        }

        .pill-clear {
          background: none; border: none; color: rgba(0,255,200,0.5);
          cursor: pointer; font-size: 14px; line-height: 1; padding: 0;
          transition: color 0.2s;
        }
        .pill-clear:hover { color: #00ffc8; }

        /* Question list wrapper */
        .qlist-wrap {
          position: relative;
        }

        /* Bracket decoration on main panel */
        .panel {
          position: relative;
          border: 1px solid rgba(0,255,200,0.1);
          padding: 24px;
          background: rgba(2,12,20,0.5);
          backdrop-filter: blur(12px);
        }

        .panel-brk { position: absolute; width: 16px; height: 16px; }
        .panel-brk-tl { top: -1px; left: -1px; border-top: 1px solid rgba(0,255,200,0.5); border-left: 1px solid rgba(0,255,200,0.5); }
        .panel-brk-tr { top: -1px; right: -1px; border-top: 1px solid rgba(0,255,200,0.5); border-right: 1px solid rgba(0,255,200,0.5); }
        .panel-brk-bl { bottom: -1px; left: -1px; border-bottom: 1px solid rgba(0,255,200,0.5); border-left: 1px solid rgba(0,255,200,0.5); }
        .panel-brk-br { bottom: -1px; right: -1px; border-bottom: 1px solid rgba(0,255,200,0.5); border-right: 1px solid rgba(0,255,200,0.5); }
      `}</style>

      <div className="home-root">
        <div className="scanlines" />
        <div className="scan-beam" style={{ top: `${scanY}%` }} />

        {/* Top bar */}
        <nav className={`topbar ${mounted ? "on" : ""}`}>
          <div className="topbar-logo">Stack<span>Query</span></div>
          <div className="topbar-right">
            <div className="topbar-stat"><strong>1,204</strong> questions</div>
            <div className="topbar-stat"><strong>342</strong> users</div>
            <div className="topbar-dot" />
          </div>
        </nav>

        <div className={`layout ${mounted ? "on" : ""}`}>
          {/* Sidebar */}
          <aside className="sidebar">
            <div className="sidebar-header">
              <span className="sidebar-title">Tags</span>
              <div className="sidebar-title-line" />
            </div>

            {TAGS.map((tag, i) => (
              <div
                key={tag.name}
                className={`tag-item ${activeTag === tag.name ? "active" : ""}`}
                style={{ animationDelay: `${i * 0.04}s` }}
                onClick={() => setActiveTag(activeTag === tag.name ? null : tag.name)}
              >
                <div className="tag-left">
                  <span className="tag-arrow">▶</span>
                  {tag.name}
                </div>
                <span className="tag-count">{tag.count}</span>
              </div>
            ))}
          </aside>

          {/* Main */}
          <main className="main">
            <div className="main-header">
              <div className="main-title-group">
                <div className="main-eyebrow">// Browse knowledge base</div>
                <h1 className="main-title">
                  All <span className="main-title-accent">Questions</span>
                </h1>
              </div>
              <button className="ask-btn">
                <span className="ask-btn-plus">+</span>
                Ask Question
              </button>
            </div>

            <div className="filter-bar">
              {["Latest", "Active", "Unanswered", "Hot"].map((f, i) => (
                <button key={f} className={`filter-btn ${i === 0 ? "active" : ""}`}>{f}</button>
              ))}
              <div className="filter-sep" />
              <span className="result-count">
                {activeTag ? `Filtered: ${activeTag}` : "1,204 results"}
              </span>
            </div>

            {activeTag && (
              <div className="active-tag-pill">
                <span>tag: {activeTag}</span>
                <button className="pill-clear" onClick={() => setActiveTag(null)}>×</button>
              </div>
            )}

            <div className="panel">
              <div className="panel-brk panel-brk-tl" />
              <div className="panel-brk panel-brk-tr" />
              <div className="panel-brk panel-brk-bl" />
              <div className="panel-brk panel-brk-br" />
              <div className="qlist-wrap">
                <QuestionList activeTag={activeTag} />
              </div>
            </div>
          </main>
        </div>
      </div>
    </>
  );
}
